"""-----------------------------------------------------------------------------------------merge_fig_prf.py-----------------------------------------------------------------------------------------Goal of the script:Concat all pycortex maps and prf figures of one subject in one pdf-----------------------------------------------------------------------------------------Input(s):sys.argv[1]: main project directorysys.argv[2]: project name (corresponds to directory)sys.argv[3]: subject numbersys.argv[4]: analysis name (e.g prf)sys.argv[5]: group-----------------------------------------------------------------------------------------Output(s):one pdf file with pycortex maps and one pdf file with prf figures-----------------------------------------------------------------------------------------To run:0. To Run on meso (not on node)1. cd to function>>  cd ~/projects/pRF_analysis/analysis_code/postproc/prf/postfit2. run python command>> python merge_fig_prf.py [main directory] [project name] [subject num] [analysis name] [group]-----------------------------------------------------------------------------------------Exemple:cd ~/projects/pRF_analysis/analysis_code/postproc/prf/postfitpython merge_fig_prf.py /scratch/mszinte/data RetinoMaps sub-01 prf 327python merge_fig_prf.py /scratch/mszinte/data RetinoMaps sub-hcp1.6mm prf 327python merge_fig_prf.py /scratch/mszinte/data RetinoMaps group prf 327python merge_fig_prf.py /scratch/mszinte/data amblyo7T_prf sub-02 prf 327-----------------------------------------------------------------------------------------Written by Uriel Lascombes (uriel.lascombes@laposte.net)Edited by Martin Szinte (martin.szinte@gmail.com)-----------------------------------------------------------------------------------------"""# General importsimport osimport sysimport globfrom pypdf import PdfWriter# Personal importssys.path.append("{}/../../../utils".format(os.getcwd()))from settings_utils import load_settings# Debugimport ipdbdeb = ipdb.set_trace# Inputsmain_dir = sys.argv[1]project_dir = sys.argv[2]subject = sys.argv[3]analysis_name = sys.argv[4]group = sys.argv[5]# load settings# Load settingsbase_dir = os.path.abspath(os.path.join(os.getcwd(), "../../../../"))general_settings_path = os.path.join(base_dir, project_dir, "settings.yml")analysis_settings_path = os.path.join(base_dir, project_dir, f"{analysis_name}-analysis.yml")settings = load_settings([general_settings_path, analysis_settings_path])analysis_info = settings[0]formats = analysis_info['formats']extensions = analysis_info['extensions']preproc_prep = analysis_info['preproc_prep']filtering = analysis_info['filtering']normalization = analysis_info['normalization']avg_methods = analysis_info['avg_methods']task_names = analysis_info['analysis_task_names']rois_methods = analysis_info['rois_methods']output_folder = analysis_info["output_folder"]dm_name = analysis_info["dm_name"]# define pp dirpp_dir = '{}/{}/derivatives/pp_data'.format(main_dir, project_dir)for avg_method in avg_methods:            for format_, extension in zip(formats, extensions):           # Define output directory and file        prf_merge_dir = f'{pp_dir}/{subject}/{format_}/{output_folder}/merged'        os.makedirs(prf_merge_dir, exist_ok = True)                # define list of rois for each format        rois_methods_format = rois_methods[format_]        for rois_method_format in rois_methods_format:            for prf_task_name in prf_task_names:                # define fn                fn_spec = f"task-{task_name}_{preproc_prep}_{filtering}_{normalization}_{avg_method}"                fn_spec_rois = f"task-{task_name}_{preproc_prep}_{filtering}_{normalization}_{avg_method}_{rois_method_format}"                    # Find flatmaps                prf_flatmaps_fns = []                prf_flatmaps_fns.extend(glob.glob(                    "{}/{}/{}/corr/pycortex/flatmaps_corr/*{}*.pdf".format(                        pp_dir, subject, format_, task_name)))                prf_flatmaps_fns.extend(glob.glob(                    "{}/{}/{}/prf/pycortex/flatmaps_gauss/*{}*.pdf".format(                        pp_dir, subject, format_, fn_spec)))                prf_flatmaps_fns.extend(glob.glob(                    "{}/{}/{}/prf/pycortex/flatmaps_css/*{}*.pdf".format(                        pp_dir, subject, format_, fn_spec_rois)))                                # Sort the list alphabetically                prf_flatmaps_fns = sorted(prf_flatmaps_fns)                    # Merge pdf and export final pdf                 prf_flatmaps_merged_fn = f'{prf_merge_dir}/{subject}_{fn_spec_rois}_{analysis_name}{dm_name}_flatmaps.pdf'                    if 'group' not in subject:                    prf_flatmaps_merger = PdfWriter()                    for n_page, prf_flatmaps_fn in enumerate(prf_flatmaps_fns):                         prf_flatmaps_merger.append(prf_flatmaps_fn)                                            # Export the pdf                     print("Saving {}".format(prf_flatmaps_merged_fn))                    prf_flatmaps_merger.write(prf_flatmaps_merged_fn)                    prf_flatmaps_merger.close()                    # Find figures                prf_figures_fns = []                prf_figures_fns.extend(glob.glob(f"{pp_dir}/{subject}/{format_}/{output_folder}/figures/*{fn_spec_rois}*.pdf"))                    # Sort the list alphabetically                prf_figures_fns = sorted(prf_figures_fns)                    # Merge pdf and export final pdf                 prf_figures_merged_fn = f'{prf_merge_dir}/{subject}_{fn_spec_rois}_{analysis_name}-css{dm_name}_figures.pdf'                                prf_figures_merger = PdfWriter()                for n_page, prf_figures_fn in enumerate(prf_figures_fns):                     print(prf_figures_fn)                    prf_figures_merger.append(prf_figures_fn)                                    # Export the pdf                 print("Saving {}".format(prf_figures_merged_fn))                prf_figures_merger.write(prf_figures_merged_fn)                prf_figures_merger.close()        # Define permission cmdprint('Changing files permissions in {}/{}'.format(main_dir, project_dir))os.system("chmod -Rf 771 {}/{}".format(main_dir, project_dir))os.system("chgrp -Rf {} {}/{}".format(group, main_dir, project_dir))